public static String toTitleCase(String input) {
 if (input == null || input.isEmpty()) {
 return input;
 }

 String[] words = input.trim().split("\\s+");
 StringBuilder result = new StringBuilder();

 for (String word : words) {
 if (word.length() > 0) {
 String capitalized = word.substring(0, 1).toUpperCase() 
 + word.substring(1).toLowerCase();
 result.append(capitalized).append(" ");
 }
 }

 return result.toString().trim();
}

public static boolean compareIgnoreCase(String s1, String s2) {
 // Approach 1: Using built-in method (recommended)
 if (s1 == null || s2 == null) {
 return s1 == s2; // Both null returns true
 }
 return s1.equalsIgnoreCase(s2);

 // Approach 2: Manual conversion (educational)
 // return s1.toLowerCase().equals(s2.toLowerCase());
}

public static int countVowels(String str) {
 if (str == null) {
 return 0;
 }

 String lower = str.toLowerCase();
 int count = 0;

 for (int i = 0; i < lower.length(); i++) {
 char c = lower.charAt(i);
 if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
 count++;
 }
 }
 return count;
}

// Usage with Turkish locale
public static String toTurkishUpperCase(String input) {
 if (input == null) return null;
 return input.toUpperCase(Locale.forLanguageTag("tr"));
}

public static String reverseCase(String input) {
 if (input == null || input.isEmpty()) {
 return input;
 }

 char[] chars = input.toCharArray();

 for (int i = 0; i < chars.length; i++) {
 char c = chars[i];
 if (Character.isUpperCase(c)) {
 chars[i] = Character.toLowerCase(c);
 } else if (Character.isLowerCase(c)) {
 chars[i] = Character.toUpperCase(c);
 }
 // Digits and symbols remain unchanged
 }

 return new String(chars);
}

